def require_positive(x: int) -> int:
    assert x > 0
    return x

def bounded_score(score: int) -> int:
    assert score <= 100
    return score

def non_negative_balance(balance: int) -> int:
    assert balance >= 0
    return balance

def threshold_gap(value: int, threshold: int) -> int:
    assert value < threshold
    return threshold - value

def valid_percent(percent: int) -> int:
    assert percent >= 0 and percent <= 100
    return percent

def guarded_but_too_weak(x: int) -> int:
    if x >= 0:
        assert x > 10
    return x

def upper_limit_check(value: int, limit: int) -> int:
    if limit > 0:
        assert value < limit
    return value

def ordered_pair(left: int, right: int) -> int:
    assert left <= right
    return right - left

def branch_assertion(amount: int, flag: bool) -> int:
    if flag:
        return amount
    assert amount > 0
    return amount

def nonzero_total(total: int) -> int:
    assert total != 0
    return total

def score_lower_bound(score: int) -> int:
    if score < 100:
        assert score >= 0
    return score

def even_count(count: int) -> int:
    assert count % 2 == 0
    return count

def nonzero_positive(value: int) -> int:
    if value != 0:
        assert value > 0
    return value

def increasing_bounds(low: int, high: int) -> int:
    assert low < high
    return high - low

def strict_percent(percent: int) -> int:
    assert percent > 0 and percent < 100
    return percent

def guarded_negative_only(total: int, count: int) -> int:
    if count < 0:
        return 0
    return total // count

def off_by_one_denominator(total: int, count: int) -> int:
    if count < 1:
        return 0
    return total // (count - 1)

def guarded_large_denominator(total: int, denominator: int) -> int:
    if denominator > 10:
        return denominator
    return total // denominator

def conditional_zero_guard(total: int, divisor: int) -> int:
    if divisor == 0 and total > 0:
        return total
    return total // divisor

def range_width_ratio(total: int, left: int, right: int) -> int:
    width = right - left
    return total // width

def shifted_step_ratio(size: int, step: int) -> int:
    adjusted = step + 1
    return size // adjusted

def modulo_non_negative_only(value: int, mod: int) -> int:
    if mod < 0:
        return value
    return value % mod

def positive_branch_ratio(total: int, count: int) -> int:
    if count > 0:
        return total // count
    return total // count

def high_low_scale(high: int, low: int) -> int:
    denom = high - low
    return 100 // denom

def alternate_bucket(limit: int, bucket: int) -> int:
    if bucket != 0:
        return limit // bucket
    return limit // bucket

def choose_slot(values: list[int], flag: bool) -> int:
    idx = 1 if flag else 3
    return values[idx]

def guarded_next(values: list[int], index: int) -> int:
    if index < len(values):
        return values[index + 1]
    return 0

def lower_bound_only(values: list[int], index: int) -> int:
    if index >= 0:
        return values[index]
    return 0

def doubled_index(values: list[int], index: int) -> int:
    slot = index * 2
    return values[slot]

def checked_one_used_two(values: list[int], pos: int) -> int:
    if pos + 1 < len(values):
        return values[pos + 2]
    return 0

def branch_slot(values: list[int], flag: bool) -> int:
    idx = 3 if flag else 0
    return values[idx]

def length_one_assumption(values: list[int]) -> int:
    if len(values) > 0:
        return values[1]
    return 0

def inclusive_upper_bound(values: list[int], index: int) -> int:
    if index <= len(values):
        return values[index]
    return 0

def shifted_by_length(values: list[int], start: int) -> int:
    offset = start + len(values)
    return values[offset]

def safe_ratio(total: int, count: int) -> int:
    if count == 0:
        return 0
    return total // count

def safe_get(values: list[int], index: int) -> int:
    if index < 0 or index >= len(values):
        return 0
    return values[index]

def clamp_score(score: int) -> int:
    if score < 0:
        return 0
    if score > 100:
        return 100
    assert score >= 0 and score <= 100
    return score

def safe_mod(value: int, scale: int) -> int:
    if scale == 0:
        return value
    return value % scale

def safe_next(values: list[int], pos: int) -> int:
    next_pos = pos + 1
    if next_pos < 0 or next_pos >= len(values):
        return 0
    return values[next_pos]

def guarded_count_ratio(total: int, count: int) -> int:
    if count <= 0:
        return 0
    return total // count

def guarded_next_value(values: list[int], index: int) -> int:
    next_index = index + 1
    if next_index < 0 or next_index >= len(values):
        return 0
    return values[next_index]

def checked_positive(x: int) -> int:
    if x <= 0:
        return 0
    assert x > 0
    return x

def guarded_shifted_denominator(total: int, count: int) -> int:
    if count == 1:
        return total
    return total // (count - 1)

def guarded_second(values: list[int]) -> int:
    if len(values) <= 1:
        return 0
    return values[1]

def route_request(role: int, secure: bool, internal: bool, retry: int) -> bool:
    if (role == 1 and secure) or (role == 2 and internal and retry < 3) or (role == 3 and secure and internal):
        return True
    return False

def is_valid_transition(state: int, target: int, locked: bool, admin: bool) -> bool:
    if locked and not admin:
        return False
    return (state == 0 and target in [1, 2]) or (state == 1 and target == 2) or (admin and target >= 0)

def choose_strategy(size: int, retries: int, cached: bool, urgent: bool) -> int:
    if (urgent and retries < 2) or (cached and size < 100) or (size > 1000 and retries == 0):
        return 1
    if (not urgent and cached) or (retries > 5 and size < 500):
        return 2
    return 3

def summarize_invoice(items: list[int], tax_rate: int) -> int:
    subtotal = 0
    discount = 0
    fees = 0
    for item in items:
        if item > 100:
            discount += 5
        subtotal += item
    if subtotal > 500:
        discount += 20
    if subtotal < 50:
        fees += 10
    taxable = subtotal - discount
    tax = taxable * tax_rate // 100
    total = taxable + tax + fees
    if total < 0:
        total = 0
    return total

def classify_order(quantity: int, price: int, region: int) -> int:
    score = 0
    if quantity > 10:
        score += 2
    if quantity > 100:
        score += 5
    if price > 50:
        score += 3
    if region == 1:
        score += 1
    if region == 2:
        score += 2
    if score > 8:
        return 3
    if score > 4:
        return 2
    return 1

def normalize_scores(values: list[int]) -> list[int]:
    result: list[int] = []
    minimum = 0
    maximum = 0
    first = True
    for value in values:
        if first:
            minimum = value
            maximum = value
            first = False
        if value < minimum:
            minimum = value
        if value > maximum:
            maximum = value
    span = maximum - minimum
    for value in values:
        if span == 0:
            result.append(0)
        else:
            result.append((value - minimum) * 100 // span)
    return result

def build_status(code: int, retries: int, timeout: int) -> str:
    status = "ok"
    if code >= 500:
        status = "server"
    elif code >= 400:
        status = "client"
    elif code >= 300:
        status = "redirect"
    if retries > 0:
        status = status + ":retry"
    if retries > 3:
        status = status + ":many"
    if timeout > 10:
        status = status + ":slow"
    if timeout > 60:
        status = status + ":timeout"
    return status

def compute_shipping(weight: int, distance: int, priority: bool) -> int:
    cost = 5
    if weight > 10:
        cost += 10
    if weight > 50:
        cost += 25
    if distance > 100:
        cost += 8
    if distance > 1000:
        cost += 40
    if priority:
        cost *= 2
    if cost < 0:
        cost = 0
    if cost > 1000:
        cost = 1000
    return cost

def calculate_quote(base: int, tax: int, fee: int, discount: int, region: int, priority: bool) -> int:
    total = base + tax + fee + region
    if priority:
        total += 10
    return total - discount

def format_metric(value: int, minimum: int, maximum: int, warn: int, critical: int, enabled: bool) -> str:
    if not enabled:
        return "disabled"
    if value >= critical:
        return "critical"
    if value >= warn:
        return "warn"
    if value < minimum or value > maximum:
        return "range"
    return "ok"
